import { spawn } from "node:child_process";
import * as fs from "node:fs";
import { promises as fsp } from "node:fs";
import os from "node:os";
import path from "node:path";
import { StringDecoder } from "node:string_decoder";
import { fileURLToPath } from "node:url";
import { PROTECTED_ROOTS_ENV } from "./path-guards.ts";
import type { PiStageStreamEvent, StageExecutionResult, StageUsage } from "./types.ts";
import { normalizeMarkdown } from "./io.ts";
const STDERR_TAIL_LIMIT = 32_768;

/**
 * Resolves the guard extension path dynamically to avoid ESM/CommonJS issues
 * at module initialization time.
 */
function resolveGuardExtensionPath(): string {
	// Resolve from the package directory (works when installed as npm package)
	const __dirname = path.dirname(fileURLToPath(import.meta.url));
	const packageGuardPath = path.resolve(__dirname, "..", "artifact-guard.ts");
	if (fs.existsSync(packageGuardPath)) {
		return packageGuardPath;
	}

	// Fallback: try cwd for local development / backward compatibility
	const cwdPath = path.resolve(process.cwd(), "artifact-guard.ts");
	if (fs.existsSync(cwdPath)) {
		return cwdPath;
	}

	return packageGuardPath;
}

const GUARD_EXTENSION_PATH = resolveGuardExtensionPath();

interface AssistantMessageSummary {
	text?: string;
	stopReason?: string;
	errorMessage?: string;
	model?: string;
}

function zeroUsage(): StageUsage {
	return {
		input: 0,
		output: 0,
		cacheRead: 0,
		cacheWrite: 0,
		cost: 0,
		turns: 0,
		contextTokens: 0,
	};
}

interface PiMessagePart {
	type?: string;
	text?: string;
}

interface PiMessageCost {
	total?: number;
}

interface PiMessageUsage {
	input?: number;
	output?: number;
	cacheRead?: number;
	cacheWrite?: number;
	totalTokens?: number;
	cost?: PiMessageCost;
}

interface PiMessage {
	content?: unknown;
	stopReason?: string;
	errorMessage?: string;
	model?: string;
	usage?: PiMessageUsage;
}

function aggregateUsage(target: StageUsage, message: PiMessage): void {
	const usage = message.usage;
	if (!usage) return;
	target.turns += 1;
	target.input += usage.input ?? 0;
	target.output += usage.output ?? 0;
	target.cacheRead += usage.cacheRead ?? 0;
	target.cacheWrite += usage.cacheWrite ?? 0;
	target.cost += usage.cost?.total ?? 0;
	target.contextTokens = usage.totalTokens ?? target.contextTokens;
}

function summarizeAssistantMessage(message: PiMessage): AssistantMessageSummary {
	const text = Array.isArray(message.content)
		? (message.content as PiMessagePart[])
				.filter((part) => part?.type === "text")
				.map((part) => part.text)
				.filter((t): t is string => typeof t === "string")
				.join("\n")
		: undefined;

	return {
		text,
		stopReason: typeof message.stopReason === "string" ? message.stopReason : undefined,
		errorMessage: typeof message.errorMessage === "string" ? message.errorMessage : undefined,
		model: typeof message.model === "string" ? message.model : undefined,
	};
}

async function writeTempSystemPrompt(systemPrompt: string): Promise<{ dir: string; filePath: string }> {
	const tempDir = await fsp.mkdtemp(path.join(os.tmpdir(), "pi-idea-refinement-"));
	const filePath = path.join(tempDir, "system-prompt.md");
	await fsp.writeFile(filePath, systemPrompt, "utf8");
	return { dir: tempDir, filePath };
}

export function buildPiArgs(options: { tempPromptPath: string; userPrompt: string; model?: string; thinkingLevel?: string; cwd?: string }): string[] {
	const { tempPromptPath, userPrompt, model, thinkingLevel, cwd } = options;
	const args = [
		"--mode",
		"json",
		"-p",
		"--no-session",
		"--no-extensions",
		"--extension",
		GUARD_EXTENSION_PATH,
		"--append-system-prompt",
		tempPromptPath,
	];
	if (model) args.push("--model", model);
	if (thinkingLevel) args.push("--thinking", thinkingLevel);
	args.push(userPrompt);
	return args;
}

function getPiInvocation(args: string[]): { command: string; args: string[] } {
	const currentScript = process.argv[1];
	const isBunVirtualScript = currentScript?.startsWith("/$bunfs/root/");
	if (currentScript && !isBunVirtualScript && fs.existsSync(currentScript)) {
		// C5 fix: propagate process.execArgv (e.g. --experimental-strip-types) to subprocess
		return { command: process.execPath, args: [...process.execArgv, currentScript, ...args] };
	}

	const execName = path.basename(process.execPath).toLowerCase();
	const isGenericRuntime = /^(node|bun)(\.exe)?$/.test(execName);
	if (!isGenericRuntime) {
		return { command: process.execPath, args };
	}

	return { command: "pi", args };
}

function appendTail(current: string, next: string, maxChars: number): string {
	if (next.length >= maxChars) {
		return next.slice(-maxChars);
	}
	const available = maxChars - next.length;
	if (current.length <= available) {
		return current + next;
	}
	return current.slice(-available) + next;
}

function safeParseJson(line: string): unknown {
	try {
		return JSON.parse(line);
	} catch {
		return undefined;
	}
}

function isPiEvent(value: unknown): value is Record<string, unknown> {
	return typeof value === "object" && value !== null && typeof (value as Record<string, unknown>).type === "string";
}

// O6 fix: Remove "error" from stdout filter — errors come via stderr
function shouldPersistStdoutLogLine(line: string): boolean {
	if (line.length === 0) return false;
	if (line.includes('"type":"message_update"')) return false;
	return (
		line.includes('"type":"session"') ||
		line.includes('"type":"agent_start"') ||
		line.includes('"type":"turn_start"') ||
		line.includes('"type":"turn_end"') ||
		line.includes('"type":"message_start"') ||
		line.includes('"type":"message_end"') ||
		line.includes('"type":"tool_execution_start"') ||
		line.includes('"type":"tool_execution_end"')
	);
}

// O8 fix: Simplified JSON string extraction using regex
function extractJsonStringValueAfter(line: string, anchor: string, fieldName: string): string | undefined {
	const anchorIndex = line.indexOf(anchor);
	if (anchorIndex === -1) return undefined;

	const token = `"${fieldName}":"`;
	const match = line.slice(anchorIndex).match(new RegExp(`${token}(.*?)(?:"[,}]|$)`));
	if (!match) return undefined;

	const rawValue = match[1] ?? "";
	if (!rawValue.includes("\\")) return rawValue;

	try {
		return JSON.parse(`"${rawValue}"`);
	} catch {
		return undefined;
	}
}

async function finalizeWriteStream(stream: fs.WriteStream): Promise<void> {
	if (stream.writableFinished || stream.destroyed) {
		return;
	}

	await new Promise<void>((resolve, reject) => {
		const handleError = (error: Error) => {
			stream.off("finish", handleFinish);
			reject(error);
		};
		const handleFinish = () => {
			stream.off("error", handleError);
			resolve();
		};
		stream.once("error", handleError);
		stream.once("finish", handleFinish);
		stream.end();
	});
}

export interface RunPiStageOptions {
	cwd: string;
	model?: string;
	thinkingLevel?: string;
	systemPrompt: string;
	userPrompt: string;
	logPath: string;
	stderrPath: string;
	protectedRoots: string[];
	onProgress?: (message: string) => void;
	onEvent?: (event: PiStageStreamEvent) => void;
	/** D3 fix: Timeout in ms. Default: 10 minutes. Set to 0 to disable. */
	timeoutMs?: number;
	/**
	 * Override the subprocess invocation.
	 * `command`: the executable to run.
	 * `args`: base args prepended to the standard buildPiArgs output.
	 * Standard args (--append-system-prompt, --model, user prompt, etc.) are always appended.
	 */
	invocation?: {
		command: string;
		args?: string[];
	};
}

export async function runPiStage(options: RunPiStageOptions): Promise<StageExecutionResult> {
	const { cwd, model, thinkingLevel, systemPrompt, userPrompt, logPath, stderrPath, protectedRoots, onProgress, onEvent } = options;
	// D3 fix: Default timeout of 10 minutes. Set to 0 to disable.
	const timeoutMs = options.timeoutMs ?? 10 * 60 * 1000;
	const usage = zeroUsage();
	let lastAssistant: AssistantMessageSummary = {};
	let stderrTail = "";
	let lastProgressMessage: string | undefined;

	const tempPrompt = await writeTempSystemPrompt(systemPrompt);
	await fsp.mkdir(path.dirname(logPath), { recursive: true });
	await fsp.mkdir(path.dirname(stderrPath), { recursive: true });

	const stdoutLogStream = fs.createWriteStream(logPath, { flags: "w" });
	const stderrLogStream = fs.createWriteStream(stderrPath, { flags: "w" });

	const emitProgress = (message: string, force = false) => {
		if (!onProgress) return;
		if (!force && message === lastProgressMessage) return;
		lastProgressMessage = message;
		onProgress(message);
	};

	const emitEvent = (event: PiStageStreamEvent) => {
		onEvent?.(event);
	};

	emitProgress("Waiting for agent response...", true);

	try {
		const args = buildPiArgs({
			tempPromptPath: tempPrompt.filePath,
			userPrompt,
			model,
			thinkingLevel,
			cwd,
		});

		const invocation = options.invocation
			? { command: options.invocation.command, args: [...(options.invocation.args ?? []), ...args] }
			: getPiInvocation(args);

		const exitCode = await new Promise<number>((resolve, reject) => {
			const proc = spawn(invocation.command, invocation.args, {
				cwd,
				shell: false,
				stdio: ["ignore", "pipe", "pipe"],
				env: {
					...process.env,
					[PROTECTED_ROOTS_ENV]: JSON.stringify(protectedRoots),
				},
			});

			// D3 fix: Timeout handling
			let timeoutTimer: ReturnType<typeof setTimeout> | undefined;
			if (timeoutMs > 0) {
				timeoutTimer = setTimeout(() => {
					try { proc.kill("SIGTERM"); } catch {}
					reject(new Error(`Stage timed out after ${timeoutMs}ms`));
				}, timeoutMs);
			}

			// D4 fix: Propagate SIGTERM/SIGINT to subprocess
			const onParentSignal = () => {
				try { proc.kill("SIGTERM"); } catch {}
			};
			process.once("SIGTERM", onParentSignal);
			process.once("SIGINT", onParentSignal);

			const cleanup = () => {
				if (timeoutTimer) { clearTimeout(timeoutTimer); timeoutTimer = undefined; }
				process.off("SIGTERM", onParentSignal);
				process.off("SIGINT", onParentSignal);
			};

			const stdoutDecoder = new StringDecoder("utf8");
			const stderrDecoder = new StringDecoder("utf8");
			let buffer = "";

			const writeStdoutLogLine = (line: string) => {
				if (!shouldPersistStdoutLogLine(line)) return;
				stdoutLogStream.write(`${line}\n`);
			};

			const processLine = (line: string) => {
				if (line.length === 0) return;

				const parsed = safeParseJson(line);
				if (!isPiEvent(parsed)) return;

				if (parsed.type === "tool_execution_start") {
					const toolName = typeof parsed.toolName === "string" ? parsed.toolName : "tool";
					emitProgress(`Executing tool ${toolName}...`);
					emitEvent({ type: "tool_execution_start", toolName, args: parsed.args });
					return;
				}

				if (parsed.type === "tool_execution_end") {
					const toolName = typeof parsed.toolName === "string" ? parsed.toolName : "tool";
					const isError = parsed.isError === true;
					emitProgress(isError ? `Tool ${toolName} returned an error.` : `Tool ${toolName} completed.`);
					emitEvent({ type: "tool_execution_end", toolName, isError });
					return;
				}

				if (parsed.type === "message_update") {
					const assistantEvent = (parsed as Record<string, unknown>).assistantMessageEvent;
					if (isPiEvent(assistantEvent)) {
						if (assistantEvent.type === "thinking_start") {
							emitProgress("Analyzing instructions...");
							return;
						}
						if (assistantEvent.type === "text_start") {
							emitProgress("Drafting response...");
							emitEvent({ type: "text_start" });
							return;
						}
						if (assistantEvent.type === "text_end") {
							emitProgress("Finalizing response...");
							emitEvent({ type: "text_end" });
							return;
						}
					}
					return;
				}

				if (parsed.type !== "message_end") return;

				const msg = (parsed as Record<string, unknown>).message;
				if (typeof msg !== "object" || msg === null || typeof (msg as Record<string, unknown>).role !== "string") return;

				lastAssistant = summarizeAssistantMessage(msg as PiMessage);
				aggregateUsage(usage, msg as PiMessage);
				emitEvent({
					type: "message_end",
					text: lastAssistant.text,
					model: lastAssistant.model,
					stopReason: lastAssistant.stopReason,
					errorMessage: lastAssistant.errorMessage,
				});
				emitProgress(lastAssistant.text ? "Response received, validating output..." : "Turn completed, waiting for next step...", true);
			};

			proc.stdout.on("data", (chunk) => {
				buffer += stdoutDecoder.write(chunk);
				const lines = buffer.split("\n");
				buffer = lines.pop() ?? "";
				for (const line of lines) {
					writeStdoutLogLine(line);
					processLine(line);
				}
			});

			proc.stderr.on("data", (chunk) => {
				stderrLogStream.write(chunk);
				stderrTail = appendTail(stderrTail, stderrDecoder.write(chunk), STDERR_TAIL_LIMIT);
			});

			proc.on("error", (error) => { cleanup(); reject(error); });
			proc.on("close", (code) => {
				cleanup();
				buffer += stdoutDecoder.end();
				if (buffer.trim().length > 0) {
					const finalLine = buffer.trimEnd();
					writeStdoutLogLine(finalLine);
					processLine(finalLine);
				}
				stderrTail = appendTail(stderrTail, stderrDecoder.end(), STDERR_TAIL_LIMIT);
				// E4 fix: exitCode === null (SIGKILL/OOM) must be treated as failure
				resolve(code === null ? 1 : code);
			});
		});

		await Promise.all([finalizeWriteStream(stdoutLogStream), finalizeWriteStream(stderrLogStream)]);

		const normalizedText = lastAssistant.text ? normalizeMarkdown(lastAssistant.text) : "";
		const isFailure = exitCode !== 0 || lastAssistant.stopReason === "error" || lastAssistant.stopReason === "aborted";

		if (isFailure) {
			const reason = lastAssistant.errorMessage || stderrTail.trim() || `pi subprocess failed with exit code ${exitCode}`;
			throw new Error(reason);
		}

		if (!normalizedText) {
			throw new Error("The stage finished without a final assistant text output.");
		}

		return {
			text: normalizedText,
			exitCode,
			stderr: stderrTail,
			model: lastAssistant.model ?? model,
			stopReason: lastAssistant.stopReason,
			errorMessage: lastAssistant.errorMessage,
			usage,
		};
	} finally {
		try {
			await Promise.all([finalizeWriteStream(stdoutLogStream), finalizeWriteStream(stderrLogStream)]);
		} catch {
			stdoutLogStream.destroy();
			stderrLogStream.destroy();
		}
		try {
			await fsp.unlink(tempPrompt.filePath);
		} catch {
			// Ignore cleanup errors.
		}
		try {
			await fsp.rmdir(tempPrompt.dir);
		} catch {
			// Ignore cleanup errors.
		}
	}
}

import path from "node:path";
import { promises as fs } from "node:fs";
import { extractMarkedSections } from "./marker-parser.ts";
import { generateRandomNumber } from "./number-generator.ts";
import { writeMarkdownFile, normalizeMarkdown } from "./io.ts";
import { createInitialManifest, createLoopEntry, createStageRecord, markStageFailure, markStageRunning, markStageSuccess, saveManifest } from "./manifest.ts";
import { diffSnapshots, formatSnapshotDiff, takeSnapshot, type SnapshotDiff } from "./post-hoc-check.ts";
import { ensureLoopDirectory, findNextCallNumber, prepareCallWorkspace, toProjectRelativePath } from "./path-utils.ts";
import {
	buildChecklistUserPrompt,
	buildDevelopmentUserPrompt,
	buildEvaluationUserPrompt,
	buildInitialArtifactsUserPrompt,
	buildLearningUpdateUserPrompt,
	buildReportUserPrompt,
	CHECKLIST_SYSTEM_PROMPT,
	DEVELOPMENT_SYSTEM_PROMPT,
	EVALUATION_SYSTEM_PROMPT,
	INITIAL_ARTIFACTS_SYSTEM_PROMPT,
	LEARNING_UPDATE_SYSTEM_PROMPT,
	REPORT_SYSTEM_PROMPT,
	WORKFLOW_ASSUMPTIONS,
} from "./prompts.ts";
import { runPiStage } from "./runner.ts";
import type { DirectivePolicy, PiStageStreamEvent, StageExecutionResult, StageName, StageRecord, WorkflowManifest, WorkflowProgressEvent } from "./types.ts";
import { stageDisplayName, buildStageStatusMessage } from "./ui-monitor.ts";
import { determineDirectivePolicy, extractOverallScore } from "./validation.ts";

export interface WorkflowRunInput {
	cwd: string;
	idea: string;
	loops: number;
	modelPattern?: string;
	thinkingLevel?: string;
	onStatus?: (message: string | undefined) => void;
	onEvent?: (event: WorkflowProgressEvent) => void;
	/** T3 fix: Optional invocation override for testing. */
	invocation?: { command: string; args?: string[] };
}

export interface WorkflowRunResult {
	callDir: string;
	relativeCallDir: string;
	manifest: WorkflowManifest;
	latestScore?: number;
}

function stagePaths(cwd: string, record: StageRecord): { logPath: string; stderrPath: string } {
	return {
		logPath: path.resolve(cwd, record.logPath),
		stderrPath: path.resolve(cwd, record.stderrPath),
	};
}



function emitWorkflowEvent(
	onEvent: ((event: WorkflowProgressEvent) => void) | undefined,
	event: WorkflowProgressEvent,
): void {
	onEvent?.(event);
}

function mapPiStageEventToWorkflowEvent(options: {
	event: PiStageStreamEvent;
	relativeCallDir: string;
	requestedLoops: number;
	completedLoops: number;
	stageName: StageName;
	loopNumber?: number;
}): WorkflowProgressEvent | undefined {
	const { event, relativeCallDir, requestedLoops, completedLoops, stageName, loopNumber } = options;

	switch (event.type) {
		case "tool_execution_start":
			return {
				type: "tool_start",
				relativeCallDir,
				requestedLoops,
				completedLoops,
				stageName,
				loopNumber,
				message: `Tool ${event.toolName} started`,
				toolName: event.toolName,
			};
		case "tool_execution_end":
			return {
				type: "tool_end",
				relativeCallDir,
				requestedLoops,
				completedLoops,
				stageName,
				loopNumber,
				message: event.isError ? `Tool ${event.toolName} returned an error` : `Tool ${event.toolName} completed`,
				toolName: event.toolName,
				isError: event.isError,
			};
		default:
			return undefined;
	}
}

async function runManagedStage(options: {
	cwd: string;
	protectedRoots: string[];
	modelPattern?: string;
	thinkingLevel?: string;
	record: StageRecord;
	stageName: StageName;
	loopNumber?: number;
	requestedLoops: number;
	completedLoops: number;
	relativeCallDir: string;
	systemPrompt: string;
	userPrompt: string;
	manifest: WorkflowManifest;
	manifestPath: string;
	onStatus?: (message: string | undefined) => void;
	onEvent?: (event: WorkflowProgressEvent) => void;
	statusMessage: string;
	/** T3 fix: Optional invocation override for testing. */
	invocation?: { command: string; args?: string[] };
}): Promise<StageExecutionResult> {
	const {
		cwd,
		protectedRoots,
		modelPattern,
		thinkingLevel,
		record,
		stageName,
		loopNumber,
		requestedLoops,
		completedLoops,
		relativeCallDir,
		systemPrompt,
		userPrompt,
		manifest,
		manifestPath,
		onStatus,
		onEvent,
		statusMessage,
		invocation,
	} = options;
	markStageRunning(record);
	await saveManifest(manifestPath, manifest);
	onStatus?.(statusMessage);
	emitWorkflowEvent(onEvent, {
		type: "stage_started",
		relativeCallDir,
		requestedLoops,
		completedLoops,
		message: statusMessage,
		stageName,
		stageStatus: record.status,
		loopNumber,
	});

	try {
		const paths = stagePaths(cwd, record);
		const result = await runPiStage({
			cwd,
			model: modelPattern,
			thinkingLevel,
			systemPrompt,
			userPrompt,
			logPath: paths.logPath,
			stderrPath: paths.stderrPath,
			protectedRoots,
			invocation,
			onProgress: (detail) => {
				const message = buildStageStatusMessage(statusMessage, detail);
				onStatus?.(message);
				emitWorkflowEvent(onEvent, {
					type: "stage_progress",
					relativeCallDir,
					requestedLoops,
					completedLoops,
					message,
					stageName,
					stageStatus: record.status,
					loopNumber,
				});
			},
			onEvent: (event) => {
				const mappedEvent = mapPiStageEventToWorkflowEvent({
					event,
					relativeCallDir,
					requestedLoops,
					completedLoops,
					stageName,
					loopNumber,
				});
				if (mappedEvent) emitWorkflowEvent(onEvent, mappedEvent);
			},
		});
		markStageSuccess(record, result);
		await saveManifest(manifestPath, manifest);
		emitWorkflowEvent(onEvent, {
			type: "stage_completed",
			relativeCallDir,
			requestedLoops,
			completedLoops,
			message: `Stage completed: ${stageDisplayName(stageName)}${loopNumber ? ` (loop ${loopNumber}/${requestedLoops})` : ""}`,
			stageName,
			stageStatus: record.status,
			loopNumber,
		});
		return result;
	} catch (error) {
		markStageFailure(record, error);
		await saveManifest(manifestPath, manifest);
		emitWorkflowEvent(onEvent, {
			type: "stage_failed",
			relativeCallDir,
			requestedLoops,
			completedLoops,
			message: error instanceof Error ? error.message : String(error),
			stageName,
			stageStatus: record.status,
			loopNumber,
			isError: true,
		});
		throw error;
	}
}

export async function runIdeaRefinementWorkflow(input: WorkflowRunInput): Promise<WorkflowRunResult> {
	const { cwd, idea, loops, modelPattern, thinkingLevel, onStatus, onEvent, invocation } = input;
	const callNumber = await findNextCallNumber(path.join(cwd, "docs", "idea_refinement"));
	const workspace = await prepareCallWorkspace(cwd, callNumber);
	const relativeCallDir = toProjectRelativePath(cwd, workspace.callDir);
	const manifest = createInitialManifest({
		cwd,
		workspace,
		callNumber,
		requestedLoops: loops,
		model: modelPattern,
		thinkingLevel,
		assumptions: WORKFLOW_ASSUMPTIONS,
	});

	await writeMarkdownFile(workspace.rootFiles.idea, idea);
	await saveManifest(workspace.rootFiles.manifest, manifest);
	emitWorkflowEvent(onEvent, {
		type: "workflow_started",
		relativeCallDir,
		requestedLoops: loops,
		completedLoops: 0,
		message: `Workflow started in ${relativeCallDir}`,
	});

	let latestScore: number | undefined;

	try {
		const initialRandomNumber = generateRandomNumber();
		const directivePolicy: DirectivePolicy = determineDirectivePolicy(initialRandomNumber);
		manifest.initialRandomNumber = initialRandomNumber;
		manifest.directivePolicy = directivePolicy;
		await saveManifest(workspace.rootFiles.manifest, manifest);

		const bootstrapResult = await runManagedStage({
			cwd,
			protectedRoots: [workspace.callDir],
			modelPattern,
			thinkingLevel,
			record: manifest.bootstrap,
			stageName: "bootstrap",
			requestedLoops: loops,
			completedLoops: manifest.completedLoops,
			relativeCallDir,
			systemPrompt: INITIAL_ARTIFACTS_SYSTEM_PROMPT,
			userPrompt: buildInitialArtifactsUserPrompt({
				cwd,
				workspace,
				randomNumber: initialRandomNumber,
				policy: directivePolicy,
			}),
			manifest,
			manifestPath: workspace.rootFiles.manifest,
			onStatus,
			onEvent,
			statusMessage: `Generating initial artifacts in ${relativeCallDir}`,
			invocation,
		});

		let sections: Record<string, string>;
		try {
			sections = extractMarkedSections(bootstrapResult.text, [
				"DIRECTIVE.md",
				"LEARNING.md",
				"CRITERIA.md",
				"DIAGNOSIS.md",
				"METRICS.md",
				"BACKLOG.md",
			]);
		} catch (parseError) {
			const rawPath = path.join(workspace.callDir, "bootstrap-raw.md");
			await writeMarkdownFile(rawPath, bootstrapResult.text);
			throw new Error(
				`Failed to extract bootstrap sections; raw text preserved at ${rawPath}. Cause: ${parseError instanceof Error ? parseError.message : String(parseError)}`,
			);
		}
		await writeMarkdownFile(workspace.rootFiles.directive, sections["DIRECTIVE.md"]);
		await writeMarkdownFile(workspace.rootFiles.learning, sections["LEARNING.md"]);
		await writeMarkdownFile(workspace.rootFiles.criteria, sections["CRITERIA.md"]);
		await writeMarkdownFile(workspace.rootFiles.diagnosis, sections["DIAGNOSIS.md"]);
		await writeMarkdownFile(workspace.rootFiles.metrics, sections["METRICS.md"]);
		await writeMarkdownFile(workspace.rootFiles.backlog, sections["BACKLOG.md"]);
		await saveManifest(workspace.rootFiles.manifest, manifest);

		for (let loopNumber = 1; loopNumber <= loops; loopNumber += 1) {
			const loopRandomNumber = generateRandomNumber();
			const loopDir = await ensureLoopDirectory(workspace, loopNumber);
			const loopEntry = createLoopEntry({
				cwd,
				loopNumber,
				randomNumber: loopRandomNumber,
				loopDir,
				logsDir: workspace.logsDir,
			});
			manifest.loops.push(loopEntry);
			await saveManifest(workspace.rootFiles.manifest, manifest);

			// Snapshot C7: capture before develop to detect material changes
			// C2 fix: Snapshot C7 captures project source (cwd), not extension source
			const snapshotBefore = await takeSnapshot(cwd);

			const developResult = await runManagedStage({
				cwd,
				protectedRoots: [workspace.callDir],
				modelPattern,
				thinkingLevel,
				record: loopEntry.stages.develop,
				stageName: "develop",
				loopNumber,
				requestedLoops: loops,
				completedLoops: manifest.completedLoops,
				relativeCallDir,
				systemPrompt: DEVELOPMENT_SYSTEM_PROMPT,
				userPrompt: buildDevelopmentUserPrompt({
					cwd,
					workspace,
					loopNumber,
					requestedLoops: loops,
					randomNumber: loopRandomNumber,
				}),
				manifest,
				manifestPath: workspace.rootFiles.manifest,
				onStatus,
				onEvent,
				statusMessage: `Loop ${loopNumber}/${loops}: developing RESPONSE.md`,
				invocation,
			});
			await writeMarkdownFile(workspace.rootFiles.response, developResult.text);
			await writeMarkdownFile(path.join(loopDir, "RESPONSE.md"), developResult.text);

			// Snapshot C7: compare before/after and store diff in loopEntry
			// C2 fix: Snapshot C7 after develop also uses cwd (project root)
			const snapshotAfter = await takeSnapshot(cwd);
			const c7Diff: SnapshotDiff = diffSnapshots(snapshotBefore, snapshotAfter);
			loopEntry.c7Snapshot = {
				hasChanges: c7Diff.hasChanges,
				diffSummary: formatSnapshotDiff(c7Diff),
				changedFiles: c7Diff.changed.length + c7Diff.added.length,
			};

			// If C7=0 (no material changes), emit WARNING notification
			if (!c7Diff.hasChanges) {
				const warningMsg = `⚠ Loop ${loopNumber}/${loops}: C7=0 — no material changes to source code after develop. This indicates pseudo-execution.`;
				onStatus?.(warningMsg);
				emitWorkflowEvent(onEvent, {
					type: "stage_progress",
					relativeCallDir,
					requestedLoops: loops,
					completedLoops: manifest.completedLoops,
					message: warningMsg,
					stageName: "develop",
					stageStatus: "running",
					loopNumber,
				});
			}

			const evaluateResult = await runManagedStage({
				cwd,
				protectedRoots: [workspace.callDir],
				modelPattern,
				thinkingLevel,
				record: loopEntry.stages.evaluate,
				stageName: "evaluate",
				loopNumber,
				requestedLoops: loops,
				completedLoops: manifest.completedLoops,
				relativeCallDir,
				systemPrompt: EVALUATION_SYSTEM_PROMPT,
				userPrompt: buildEvaluationUserPrompt({
					cwd,
					workspace,
					loopNumber,
					requestedLoops: loops,
				}),
				manifest,
				manifestPath: workspace.rootFiles.manifest,
				onStatus,
				onEvent,
				statusMessage: `Loop ${loopNumber}/${loops}: evaluating FEEDBACK.md`,
				invocation,
			});
			await writeMarkdownFile(workspace.rootFiles.feedback, evaluateResult.text);
			await writeMarkdownFile(path.join(loopDir, "FEEDBACK.md"), evaluateResult.text);

			loopEntry.score = extractOverallScore(evaluateResult.text);
			if (typeof loopEntry.score === "number") latestScore = loopEntry.score;

			const learningResult = await runManagedStage({
				cwd,
				protectedRoots: [workspace.callDir],
				modelPattern,
				thinkingLevel,
				record: loopEntry.stages.learning,
				stageName: "learning",
				loopNumber,
				requestedLoops: loops,
				completedLoops: manifest.completedLoops,
				relativeCallDir,
				systemPrompt: LEARNING_UPDATE_SYSTEM_PROMPT,
				userPrompt: buildLearningUpdateUserPrompt({
					cwd,
					workspace,
					loopNumber,
					requestedLoops: loops,
				}),
				manifest,
				manifestPath: workspace.rootFiles.manifest,
				onStatus,
				onEvent,
				statusMessage: `Loop ${loopNumber}/${loops}: updating LEARNING.md`,
				invocation,
			});
			const learningSections = extractMarkedSections(learningResult.text, ["LEARNING.md", "BACKLOG.md"]);
			await writeMarkdownFile(workspace.rootFiles.learning, learningSections["LEARNING.md"]);
			await writeMarkdownFile(workspace.rootFiles.backlog, learningSections["BACKLOG.md"]);
			await writeMarkdownFile(path.join(loopDir, "LEARNING.md"), learningSections["LEARNING.md"]);
			await writeMarkdownFile(path.join(loopDir, "BACKLOG.md"), learningSections["BACKLOG.md"]);

			loopEntry.completedAt = new Date().toISOString();
			manifest.completedLoops = loopNumber;
			await saveManifest(workspace.rootFiles.manifest, manifest);
			emitWorkflowEvent(onEvent, {
				type: "loop_completed",
				relativeCallDir,
				requestedLoops: loops,
				completedLoops: manifest.completedLoops,
				message: `Loop ${loopNumber}/${loops} completed${typeof loopEntry.score === "number" ? ` • score ${loopEntry.score}/100` : ""}`,
				loopNumber,
				score: loopEntry.score,
			});
		}

		// === Final consolidation stages: REPORT.md and CHECKLIST.md ===
		// After all loops, generate the two final artifacts that consolidate the entire investigation.

		// C1 fix: Use manifest.report directly instead of creating a local StageRecord
		const reportResult = await runManagedStage({
			cwd,
			protectedRoots: [workspace.callDir],
			modelPattern,
			thinkingLevel,
			record: manifest.report,
			stageName: "report",
			requestedLoops: loops,
			completedLoops: manifest.completedLoops,
			relativeCallDir,
			systemPrompt: REPORT_SYSTEM_PROMPT,
			userPrompt: buildReportUserPrompt({
				cwd,
				workspace,
				requestedLoops: loops,
				completedLoops: manifest.completedLoops,
			}),
			manifest,
			manifestPath: workspace.rootFiles.manifest,
			onStatus,
			onEvent,
			statusMessage: `Consolidating final report: REPORT.md`,
			invocation,
		});
		await writeMarkdownFile(workspace.rootFiles.report, reportResult.text);

		// C1 fix: Use manifest.checklist directly instead of creating a local StageRecord
		const checklistResult = await runManagedStage({
			cwd,
			protectedRoots: [workspace.callDir],
			modelPattern,
			thinkingLevel,
			record: manifest.checklist,
			stageName: "checklist",
			requestedLoops: loops,
			completedLoops: manifest.completedLoops,
			relativeCallDir,
			systemPrompt: CHECKLIST_SYSTEM_PROMPT,
			userPrompt: buildChecklistUserPrompt({
				cwd,
				workspace,
				requestedLoops: loops,
				completedLoops: manifest.completedLoops,
			}),
			manifest,
			manifestPath: workspace.rootFiles.manifest,
			onStatus,
			onEvent,
			statusMessage: `Generating action checklist: CHECKLIST.md`,
			invocation,
		});
		await writeMarkdownFile(workspace.rootFiles.checklist, checklistResult.text);

		// O4 fix: workflow_completed emitted AFTER report and checklist stages complete
		manifest.status = "success";
		manifest.completedAt = new Date().toISOString();
		await saveManifest(workspace.rootFiles.manifest, manifest);
		onStatus?.(`Workflow completed in ${relativeCallDir}`);
		emitWorkflowEvent(onEvent, {
			type: "workflow_completed",
			relativeCallDir,
			requestedLoops: loops,
			completedLoops: manifest.completedLoops,
			message: `Workflow completed in ${relativeCallDir}`,
			score: latestScore,
		});

		return {
			callDir: workspace.callDir,
			relativeCallDir,
			manifest,
			latestScore,
		};
	} catch (error) {
		manifest.status = "failed";
		manifest.completedAt = new Date().toISOString();
		manifest.lastError = error instanceof Error ? error.message : String(error);
		await saveManifest(workspace.rootFiles.manifest, manifest);
		onStatus?.(`Workflow failed: ${manifest.lastError}`);
		emitWorkflowEvent(onEvent, {
			type: "workflow_failed",
			relativeCallDir,
			requestedLoops: loops,
			completedLoops: manifest.completedLoops,
			message: `Workflow failed: ${manifest.lastError}`,
			isError: true,
		});
		throw error;
	}
}

import { spawn } from "node:child_process";
import * as fs from "node:fs";
import { promises as fsp } from "node:fs";
import os from "node:os";
import path from "node:path";
import { StringDecoder } from "node:string_decoder";
import { fileURLToPath } from "node:url";
import { PROTECTED_ROOTS_ENV } from "./path-guards.ts";
import type { PiStageStreamEvent, StageExecutionResult, StageUsage } from "./types.ts";
import { normalizeMarkdown } from "./io.ts";
const STDERR_TAIL_LIMIT = 32_768;

/**
 * Resolves the guard extension path dynamically to avoid ESM/CommonJS issues
 * at module initialization time.
 */
function resolveGuardExtensionPath(): string {
	// Resolve from the package directory (works when installed as npm package)
	const __dirname = path.dirname(fileURLToPath(import.meta.url));
	const packageGuardPath = path.resolve(__dirname, "..", "artifact-guard.ts");
	if (fs.existsSync(packageGuardPath)) {
		return packageGuardPath;
	}

	// Fallback: try cwd for local development / backward compatibility
	const cwdPath = path.resolve(process.cwd(), "artifact-guard.ts");
	if (fs.existsSync(cwdPath)) {
		return cwdPath;
	}

	return packageGuardPath;
}

const GUARD_EXTENSION_PATH = resolveGuardExtensionPath();

interface AssistantMessageSummary {
	text?: string;
	stopReason?: string;
	errorMessage?: string;
	model?: string;
}

function zeroUsage(): StageUsage {
	return {
		input: 0,
		output: 0,
		cacheRead: 0,
		cacheWrite: 0,
		cost: 0,
		turns: 0,
		contextTokens: 0,
	};
}

interface PiMessagePart {
	type?: string;
	text?: string;
}

interface PiMessageCost {
	total?: number;
}

interface PiMessageUsage {
	input?: number;
	output?: number;
	cacheRead?: number;
	cacheWrite?: number;
	totalTokens?: number;
	cost?: PiMessageCost;
}

interface PiMessage {
	content?: unknown;
	stopReason?: string;
	errorMessage?: string;
	model?: string;
	usage?: PiMessageUsage;
}

function aggregateUsage(target: StageUsage, message: PiMessage): void {
	const usage = message.usage;
	if (!usage) return;
	target.turns += 1;
	target.input += usage.input ?? 0;
	target.output += usage.output ?? 0;
	target.cacheRead += usage.cacheRead ?? 0;
	target.cacheWrite += usage.cacheWrite ?? 0;
	target.cost += usage.cost?.total ?? 0;
	target.contextTokens = usage.totalTokens ?? target.contextTokens;
}

function summarizeAssistantMessage(message: PiMessage): AssistantMessageSummary {
	const text = Array.isArray(message.content)
		? (message.content as PiMessagePart[])
				.filter((part) => part?.type === "text")
				.map((part) => part.text)
				.filter((t): t is string => typeof t === "string")
				.join("\n")
		: undefined;

	return {
		text,
		stopReason: typeof message.stopReason === "string" ? message.stopReason : undefined,
		errorMessage: typeof message.errorMessage === "string" ? message.errorMessage : undefined,
		model: typeof message.model === "string" ? message.model : undefined,
	};
}

async function writeTempSystemPrompt(systemPrompt: string): Promise<{ dir: string; filePath: string }> {
	const tempDir = await fsp.mkdtemp(path.join(os.tmpdir(), "pi-idea-refinement-"));
	const filePath = path.join(tempDir, "system-prompt.md");
	await fsp.writeFile(filePath, systemPrompt, "utf8");
	return { dir: tempDir, filePath };
}

export function buildPiArgs(options: { tempPromptPath: string; userPrompt: string; model?: string; thinkingLevel?: string; cwd?: string }): string[] {
	const { tempPromptPath, userPrompt, model, thinkingLevel, cwd } = options;
	const args = [
		"--mode",
		"json",
		"-p",
		"--no-session",
		"--no-extensions",
		"--extension",
		GUARD_EXTENSION_PATH,
		"--append-system-prompt",
		tempPromptPath,
	];
	if (model) args.push("--model", model);
	if (thinkingLevel) args.push("--thinking", thinkingLevel);
	args.push(userPrompt);
	return args;
}

function getPiInvocation(args: string[]): { command: string; args: string[] } {
	const currentScript = process.argv[1];
	const isBunVirtualScript = currentScript?.startsWith("/$bunfs/root/");
	if (currentScript && !isBunVirtualScript && fs.existsSync(currentScript)) {
		// C5 fix: propagate process.execArgv (e.g. --experimental-strip-types) to subprocess
		return { command: process.execPath, args: [...process.execArgv, currentScript, ...args] };
	}

	const execName = path.basename(process.execPath).toLowerCase();
	const isGenericRuntime = /^(node|bun)(\.exe)?$/.test(execName);
	if (!isGenericRuntime) {
		return { command: process.execPath, args };
	}

	return { command: "pi", args };
}

function appendTail(current: string, next: string, maxChars: number): string {
	if (next.length >= maxChars) {
		return next.slice(-maxChars);
	}
	const available = maxChars - next.length;
	if (current.length <= available) {
		return current + next;
	}
	return current.slice(-available) + next;
}

function safeParseJson(line: string): unknown {
	try {
		return JSON.parse(line);
	} catch {
		return undefined;
	}
}

function isPiEvent(value: unknown): value is Record<string, unknown> {
	return typeof value === "object" && value !== null && typeof (value as Record<string, unknown>).type === "string";
}

// O6 fix: Remove "error" from stdout filter — errors come via stderr
function shouldPersistStdoutLogLine(line: string): boolean {
	if (line.length === 0) return false;
	if (line.includes('"type":"message_update"')) return false;
	return (
		line.includes('"type":"session"') ||
		line.includes('"type":"agent_start"') ||
		line.includes('"type":"turn_start"') ||
		line.includes('"type":"turn_end"') ||
		line.includes('"type":"message_start"') ||
		line.includes('"type":"message_end"') ||
		line.includes('"type":"tool_execution_start"') ||
		line.includes('"type":"tool_execution_end"')
	);
}

// O8 fix: Simplified JSON string extraction using regex
function extractJsonStringValueAfter(line: string, anchor: string, fieldName: string): string | undefined {
	const anchorIndex = line.indexOf(anchor);
	if (anchorIndex === -1) return undefined;

	const token = `"${fieldName}":"`;
	const match = line.slice(anchorIndex).match(new RegExp(`${token}(.*?)(?:"[,}]|$)`));
	if (!match) return undefined;

	const rawValue = match[1] ?? "";
	if (!rawValue.includes("\\")) return rawValue;

	try {
		return JSON.parse(`"${rawValue}"`);
	} catch {
		return undefined;
	}
}

async function finalizeWriteStream(stream: fs.WriteStream): Promise<void> {
	if (stream.writableFinished || stream.destroyed) {
		return;
	}

	await new Promise<void>((resolve, reject) => {
		const handleError = (error: Error) => {
			stream.off("finish", handleFinish);
			reject(error);
		};
		const handleFinish = () => {
			stream.off("error", handleError);
			resolve();
		};
		stream.once("error", handleError);
		stream.once("finish", handleFinish);
		stream.end();
	});
}

export interface RunPiStageOptions {
	cwd: string;
	model?: string;
	thinkingLevel?: string;
	systemPrompt: string;
	userPrompt: string;
	logPath: string;
	stderrPath: string;
	protectedRoots: string[];
	onProgress?: (message: string) => void;
	onEvent?: (event: PiStageStreamEvent) => void;
	/** D3 fix: Timeout in ms. Default: 10 minutes. Set to 0 to disable. */
	timeoutMs?: number;
	/**
	 * Override the subprocess invocation.
	 * `command`: the executable to run.
	 * `args`: base args prepended to the standard buildPiArgs output.
	 * Standard args (--append-system-prompt, --model, user prompt, etc.) are always appended.
	 */
	invocation?: {
		command: string;
		args?: string[];
	};
}

export async function runPiStage(options: RunPiStageOptions): Promise<StageExecutionResult> {
	const { cwd, model, thinkingLevel, systemPrompt, userPrompt, logPath, stderrPath, protectedRoots, onProgress, onEvent } = options;
	// D3 fix: Default timeout of 10 minutes. Set to 0 to disable.
	const timeoutMs = options.timeoutMs ?? 10 * 60 * 1000;
	const usage = zeroUsage();
	let lastAssistant: AssistantMessageSummary = {};
	let stderrTail = "";
	let lastProgressMessage: string | undefined;

	const tempPrompt = await writeTempSystemPrompt(systemPrompt);
	await fsp.mkdir(path.dirname(logPath), { recursive: true });
	await fsp.mkdir(path.dirname(stderrPath), { recursive: true });

	const stdoutLogStream = fs.createWriteStream(logPath, { flags: "w" });
	const stderrLogStream = fs.createWriteStream(stderrPath, { flags: "w" });

	const emitProgress = (message: string, force = false) => {
		if (!onProgress) return;
		if (!force && message === lastProgressMessage) return;
		lastProgressMessage = message;
		onProgress(message);
	};

	const emitEvent = (event: PiStageStreamEvent) => {
		onEvent?.(event);
	};

	emitProgress("Waiting for agent response...", true);

	try {
		const args = buildPiArgs({
			tempPromptPath: tempPrompt.filePath,
			userPrompt,
			model,
			thinkingLevel,
			cwd,
		});

		const invocation = options.invocation
			? { command: options.invocation.command, args: [...(options.invocation.args ?? []), ...args] }
			: getPiInvocation(args);

		const exitCode = await new Promise<number>((resolve, reject) => {
			const proc = spawn(invocation.command, invocation.args, {
				cwd,
				shell: false,
				stdio: ["ignore", "pipe", "pipe"],
				env: {
					...process.env,
					[PROTECTED_ROOTS_ENV]: JSON.stringify(protectedRoots),
				},
			});

			// D3 fix: Timeout handling
			let timeoutTimer: ReturnType<typeof setTimeout> | undefined;
			if (timeoutMs > 0) {
				timeoutTimer = setTimeout(() => {
					try { proc.kill("SIGTERM"); } catch {}
					reject(new Error(`Stage timed out after ${timeoutMs}ms`));
				}, timeoutMs);
			}

			// D4 fix: Propagate SIGTERM/SIGINT to subprocess
			const onParentSignal = () => {
				try { proc.kill("SIGTERM"); } catch {}
			};
			process.once("SIGTERM", onParentSignal);
			process.once("SIGINT", onParentSignal);

			const cleanup = () => {
				if (timeoutTimer) { clearTimeout(timeoutTimer); timeoutTimer = undefined; }
				process.off("SIGTERM", onParentSignal);
				process.off("SIGINT", onParentSignal);
			};

			const stdoutDecoder = new StringDecoder("utf8");
			const stderrDecoder = new StringDecoder("utf8");
			let buffer = "";

			const writeStdoutLogLine = (line: string) => {
				if (!shouldPersistStdoutLogLine(line)) return;
				stdoutLogStream.write(`${line}\n`);
			};

			const processLine = (line: string) => {
				if (line.length === 0) return;

				const parsed = safeParseJson(line);
				if (!isPiEvent(parsed)) return;

				if (parsed.type === "tool_execution_start") {
					const toolName = typeof parsed.toolName === "string" ? parsed.toolName : "tool";
					emitProgress(`Executing tool ${toolName}...`);
					emitEvent({ type: "tool_execution_start", toolName, args: parsed.args });
					return;
				}

				if (parsed.type === "tool_execution_end") {
					const toolName = typeof parsed.toolName === "string" ? parsed.toolName : "tool";
					const isError = parsed.isError === true;
					emitProgress(isError ? `Tool ${toolName} returned an error.` : `Tool ${toolName} completed.`);
					emitEvent({ type: "tool_execution_end", toolName, isError });
					return;
				}

				if (parsed.type === "message_update") {
					const assistantEvent = (parsed as Record<string, unknown>).assistantMessageEvent;
					if (isPiEvent(assistantEvent)) {
						if (assistantEvent.type === "thinking_start") {
							emitProgress("Analyzing instructions...");
							return;
						}
						if (assistantEvent.type === "text_start") {
							emitProgress("Drafting response...");
							emitEvent({ type: "text_start" });
							return;
						}
						if (assistantEvent.type === "text_end") {
							emitProgress("Finalizing response...");
							emitEvent({ type: "text_end" });
							return;
						}
					}
					return;
				}

				if (parsed.type !== "message_end") return;

				const msg = (parsed as Record<string, unknown>).message;
				if (typeof msg !== "object" || msg === null || typeof (msg as Record<string, unknown>).role !== "string") return;

				lastAssistant = summarizeAssistantMessage(msg as PiMessage);
				aggregateUsage(usage, msg as PiMessage);
				emitEvent({
					type: "message_end",
					text: lastAssistant.text,
					model: lastAssistant.model,
					stopReason: lastAssistant.stopReason,
					errorMessage: lastAssistant.errorMessage,
				});
				emitProgress(lastAssistant.text ? "Response received, validating output..." : "Turn completed, waiting for next step...", true);
			};

			proc.stdout.on("data", (chunk) => {
				buffer += stdoutDecoder.write(chunk);
				const lines = buffer.split("\n");
				buffer = lines.pop() ?? "";
				for (const line of lines) {
					writeStdoutLogLine(line);
					processLine(line);
				}
			});

			proc.stderr.on("data", (chunk) => {
				stderrLogStream.write(chunk);
				stderrTail = appendTail(stderrTail, stderrDecoder.write(chunk), STDERR_TAIL_LIMIT);
			});

			proc.on("error", (error) => { cleanup(); reject(error); });
			proc.on("close", (code) => {
				cleanup();
				buffer += stdoutDecoder.end();
				if (buffer.trim().length > 0) {
					const finalLine = buffer.trimEnd();
					writeStdoutLogLine(finalLine);
					processLine(finalLine);
				}
				stderrTail = appendTail(stderrTail, stderrDecoder.end(), STDERR_TAIL_LIMIT);
				// E4 fix: exitCode === null (SIGKILL/OOM) must be treated as failure
				resolve(code === null ? 1 : code);
			});
		});

		await Promise.all([finalizeWriteStream(stdoutLogStream), finalizeWriteStream(stderrLogStream)]);

		const normalizedText = lastAssistant.text ? normalizeMarkdown(lastAssistant.text) : "";
		const isFailure = exitCode !== 0 || lastAssistant.stopReason === "error" || lastAssistant.stopReason === "aborted";

		if (isFailure) {
			const reason = lastAssistant.errorMessage || stderrTail.trim() || `pi subprocess failed with exit code ${exitCode}`;
			throw new Error(reason);
		}

		if (!normalizedText) {
			throw new Error("The stage finished without a final assistant text output.");
		}

		return {
			text: normalizedText,
			exitCode,
			stderr: stderrTail,
			model: lastAssistant.model ?? model,
			stopReason: lastAssistant.stopReason,
			errorMessage: lastAssistant.errorMessage,
			usage,
		};
	} finally {
		try {
			await Promise.all([finalizeWriteStream(stdoutLogStream), finalizeWriteStream(stderrLogStream)]);
		} catch {
			stdoutLogStream.destroy();
			stderrLogStream.destroy();
		}
		try {
			await fsp.unlink(tempPrompt.filePath);
		} catch {
			// Ignore cleanup errors.
		}
		try {
			await fsp.rmdir(tempPrompt.dir);
		} catch {
			// Ignore cleanup errors.
		}
	}
}

import { spawn } from "node:child_process";
import * as fs from "node:fs";
import { promises as fsp } from "node:fs";
import os from "node:os";
import path from "node:path";
import { StringDecoder } from "node:string_decoder";
import { fileURLToPath } from "node:url";
import { PROTECTED_ROOTS_ENV } from "./path-guards.ts";
import type { PiStageStreamEvent, StageExecutionResult, StageUsage } from "./types.ts";
import { normalizeMarkdown } from "./io.ts";
const STDERR_TAIL_LIMIT = 32_768;

/**
 * Resolves the guard extension path dynamically to avoid ESM/CommonJS issues
 * at module initialization time.
 */
function resolveGuardExtensionPath(): string {
	// Resolve from the package directory (works when installed as npm package)
	const __dirname = path.dirname(fileURLToPath(import.meta.url));
	const packageGuardPath = path.resolve(__dirname, "..", "artifact-guard.ts");
	if (fs.existsSync(packageGuardPath)) {
		return packageGuardPath;
	}

	// Fallback: try cwd for local development / backward compatibility
	const cwdPath = path.resolve(process.cwd(), "artifact-guard.ts");
	if (fs.existsSync(cwdPath)) {
		return cwdPath;
	}

	return packageGuardPath;
}

const GUARD_EXTENSION_PATH = resolveGuardExtensionPath();

interface AssistantMessageSummary {
	text?: string;
	stopReason?: string;
	errorMessage?: string;
	model?: string;
}

function zeroUsage(): StageUsage {
	return {
		input: 0,
		output: 0,
		cacheRead: 0,
		cacheWrite: 0,
		cost: 0,
		turns: 0,
		contextTokens: 0,
	};
}

interface PiMessagePart {
	type?: string;
	text?: string;
}

interface PiMessageCost {
	total?: number;
}

interface PiMessageUsage {
	input?: number;
	output?: number;
	cacheRead?: number;
	cacheWrite?: number;
	totalTokens?: number;
	cost?: PiMessageCost;
}

interface PiMessage {
	content?: unknown;
	stopReason?: string;
	errorMessage?: string;
	model?: string;
	usage?: PiMessageUsage;
}

function aggregateUsage(target: StageUsage, message: PiMessage): void {
	const usage = message.usage;
	if (!usage) return;
	target.turns += 1;
	target.input += usage.input ?? 0;
	target.output += usage.output ?? 0;
	target.cacheRead += usage.cacheRead ?? 0;
	target.cacheWrite += usage.cacheWrite ?? 0;
	target.cost += usage.cost?.total ?? 0;
	target.contextTokens = usage.totalTokens ?? target.contextTokens;
}

function summarizeAssistantMessage(message: PiMessage): AssistantMessageSummary {
	const text = Array.isArray(message.content)
		? (message.content as PiMessagePart[])
				.filter((part) => part?.type === "text")
				.map((part) => part.text)
				.filter((t): t is string => typeof t === "string")
				.join("\n")
		: undefined;

	return {
		text,
		stopReason: typeof message.stopReason === "string" ? message.stopReason : undefined,
		errorMessage: typeof message.errorMessage === "string" ? message.errorMessage : undefined,
		model: typeof message.model === "string" ? message.model : undefined,
	};
}

async function writeTempSystemPrompt(systemPrompt: string): Promise<{ dir: string; filePath: string }> {
	const tempDir = await fsp.mkdtemp(path.join(os.tmpdir(), "pi-idea-refinement-"));
	const filePath = path.join(tempDir, "system-prompt.md");
	await fsp.writeFile(filePath, systemPrompt, "utf8");
	return { dir: tempDir, filePath };
}

export function buildPiArgs(options: { tempPromptPath: string; userPrompt: string; model?: string; thinkingLevel?: string; cwd?: string }): string[] {
	const { tempPromptPath, userPrompt, model, thinkingLevel, cwd } = options;
	const args = [
		"--mode",
		"json",
		"-p",
		"--no-session",
		"--no-extensions",
		"--extension",
		GUARD_EXTENSION_PATH,
		"--append-system-prompt",
		tempPromptPath,
	];
	if (model) args.push("--model", model);
	if (thinkingLevel) args.push("--thinking", thinkingLevel);
	args.push(userPrompt);
	return args;
}

function getPiInvocation(args: string[]): { command: string; args: string[] } {
	const currentScript = process.argv[1];
	const isBunVirtualScript = currentScript?.startsWith("/$bunfs/root/");
	if (currentScript && !isBunVirtualScript && fs.existsSync(currentScript)) {
		// C5 fix: propagate process.execArgv (e.g. --experimental-strip-types) to subprocess
		return { command: process.execPath, args: [...process.execArgv, currentScript, ...args] };
	}

	const execName = path.basename(process.execPath).toLowerCase();
	const isGenericRuntime = /^(node|bun)(\.exe)?$/.test(execName);
	if (!isGenericRuntime) {
		return { command: process.execPath, args };
	}

	return { command: "pi", args };
}

function appendTail(current: string, next: string, maxChars: number): string {
	if (next.length >= maxChars) {
		return next.slice(-maxChars);
	}
	const available = maxChars - next.length;
	if (current.length <= available) {
		return current + next;
	}
	return current.slice(-available) + next;
}

function safeParseJson(line: string): unknown {
	try {
		return JSON.parse(line);
	} catch {
		return undefined;
	}
}

function isPiEvent(value: unknown): value is Record<string, unknown> {
	return typeof value === "object" && value !== null && typeof (value as Record<string, unknown>).type === "string";
}

// O6 fix: Remove "error" from stdout filter — errors come via stderr
function shouldPersistStdoutLogLine(line: string): boolean {
	if (line.length === 0) return false;
	if (line.includes('"type":"message_update"')) return false;
	return (
		line.includes('"type":"session"') ||
		line.includes('"type":"agent_start"') ||
		line.includes('"type":"turn_start"') ||
		line.includes('"type":"turn_end"') ||
		line.includes('"type":"message_start"') ||
		line.includes('"type":"message_end"') ||
		line.includes('"type":"tool_execution_start"') ||
		line.includes('"type":"tool_execution_end"')
	);
}

// O8 fix: Simplified JSON string extraction using regex
function extractJsonStringValueAfter(line: string, anchor: string, fieldName: string): string | undefined {
	const anchorIndex = line.indexOf(anchor);
	if (anchorIndex === -1) return undefined;

	const token = `"${fieldName}":"`;
	const match = line.slice(anchorIndex).match(new RegExp(`${token}(.*?)(?:"[,}]|$)`));
	if (!match) return undefined;

	const rawValue = match[1] ?? "";
	if (!rawValue.includes("\\")) return rawValue;

	try {
		return JSON.parse(`"${rawValue}"`);
	} catch {
		return undefined;
	}
}

async function finalizeWriteStream(stream: fs.WriteStream): Promise<void> {
	if (stream.writableFinished || stream.destroyed) {
		return;
	}

	await new Promise<void>((resolve, reject) => {
		const handleError = (error: Error) => {
			stream.off("finish", handleFinish);
			reject(error);
		};
		const handleFinish = () => {
			stream.off("error", handleError);
			resolve();
		};
		stream.once("error", handleError);
		stream.once("finish", handleFinish);
		stream.end();
	});
}

export interface RunPiStageOptions {
	cwd: string;
	model?: string;
	thinkingLevel?: string;
	systemPrompt: string;
	userPrompt: string;
	logPath: string;
	stderrPath: string;
	protectedRoots: string[];
	onProgress?: (message: string) => void;
	onEvent?: (event: PiStageStreamEvent) => void;
	/** D3 fix: Timeout in ms. Default: 10 minutes. Set to 0 to disable. */
	timeoutMs?: number;
	/**
	 * Override the subprocess invocation.
	 * `command`: the executable to run.
	 * `args`: base args prepended to the standard buildPiArgs output.
	 * Standard args (--append-system-prompt, --model, user prompt, etc.) are always appended.
	 */
	invocation?: {
		command: string;
		args?: string[];
	};
}

export async function runPiStage(options: RunPiStageOptions): Promise<StageExecutionResult> {
	const { cwd, model, thinkingLevel, systemPrompt, userPrompt, logPath, stderrPath, protectedRoots, onProgress, onEvent } = options;
	// D3 fix: Default timeout of 10 minutes. Set to 0 to disable.
	const timeoutMs = options.timeoutMs ?? 10 * 60 * 1000;
	const usage = zeroUsage();
	let lastAssistant: AssistantMessageSummary = {};
	let stderrTail = "";
	let lastProgressMessage: string | undefined;

	const tempPrompt = await writeTempSystemPrompt(systemPrompt);
	await fsp.mkdir(path.dirname(logPath), { recursive: true });
	await fsp.mkdir(path.dirname(stderrPath), { recursive: true });

	const stdoutLogStream = fs.createWriteStream(logPath, { flags: "w" });
	const stderrLogStream = fs.createWriteStream(stderrPath, { flags: "w" });

	const emitProgress = (message: string, force = false) => {
		if (!onProgress) return;
		if (!force && message === lastProgressMessage) return;
		lastProgressMessage = message;
		onProgress(message);
	};

	const emitEvent = (event: PiStageStreamEvent) => {
		onEvent?.(event);
	};

	emitProgress("Waiting for agent response...", true);

	try {
		const args = buildPiArgs({
			tempPromptPath: tempPrompt.filePath,
			userPrompt,
			model,
			thinkingLevel,
			cwd,
		});

		const invocation = options.invocation
			? { command: options.invocation.command, args: [...(options.invocation.args ?? []), ...args] }
			: getPiInvocation(args);

		const exitCode = await new Promise<number>((resolve, reject) => {
			const proc = spawn(invocation.command, invocation.args, {
				cwd,
				shell: false,
				stdio: ["ignore", "pipe", "pipe"],
				env: {
					...process.env,
					[PROTECTED_ROOTS_ENV]: JSON.stringify(protectedRoots),
				},
			});

			// D3 fix: Timeout handling
			let timeoutTimer: ReturnType<typeof setTimeout> | undefined;
			if (timeoutMs > 0) {
				timeoutTimer = setTimeout(() => {
					try { proc.kill("SIGTERM"); } catch {}
					reject(new Error(`Stage timed out after ${timeoutMs}ms`));
				}, timeoutMs);
			}

			// D4 fix: Propagate SIGTERM/SIGINT to subprocess
			const onParentSignal = () => {
				try { proc.kill("SIGTERM"); } catch {}
			};
			process.once("SIGTERM", onParentSignal);
			process.once("SIGINT", onParentSignal);

			const cleanup = () => {
				if (timeoutTimer) { clearTimeout(timeoutTimer); timeoutTimer = undefined; }
				process.off("SIGTERM", onParentSignal);
				process.off("SIGINT", onParentSignal);
			};

			const stdoutDecoder = new StringDecoder("utf8");
			const stderrDecoder = new StringDecoder("utf8");
			let buffer = "";

			const writeStdoutLogLine = (line: string) => {
				if (!shouldPersistStdoutLogLine(line)) return;
				stdoutLogStream.write(`${line}\n`);
			};

			const processLine = (line: string) => {
				if (line.length === 0) return;

				const parsed = safeParseJson(line);
				if (!isPiEvent(parsed)) return;

				if (parsed.type === "tool_execution_start") {
					const toolName = typeof parsed.toolName === "string" ? parsed.toolName : "tool";
					emitProgress(`Executing tool ${toolName}...`);
					emitEvent({ type: "tool_execution_start", toolName, args: parsed.args });
					return;
				}

				if (parsed.type === "tool_execution_end") {
					const toolName = typeof parsed.toolName === "string" ? parsed.toolName : "tool";
					const isError = parsed.isError === true;
					emitProgress(isError ? `Tool ${toolName} returned an error.` : `Tool ${toolName} completed.`);
					emitEvent({ type: "tool_execution_end", toolName, isError });
					return;
				}

				if (parsed.type === "message_update") {
					const assistantEvent = (parsed as Record<string, unknown>).assistantMessageEvent;
					if (isPiEvent(assistantEvent)) {
						if (assistantEvent.type === "thinking_start") {
							emitProgress("Analyzing instructions...");
							return;
						}
						if (assistantEvent.type === "text_start") {
							emitProgress("Drafting response...");
							emitEvent({ type: "text_start" });
							return;
						}
						if (assistantEvent.type === "text_end") {
							emitProgress("Finalizing response...");
							emitEvent({ type: "text_end" });
							return;
						}
					}
					return;
				}

				if (parsed.type !== "message_end") return;

				const msg = (parsed as Record<string, unknown>).message;
				if (typeof msg !== "object" || msg === null || typeof (msg as Record<string, unknown>).role !== "string") return;

				lastAssistant = summarizeAssistantMessage(msg as PiMessage);
				aggregateUsage(usage, msg as PiMessage);
				emitEvent({
					type: "message_end",
					text: lastAssistant.text,
					model: lastAssistant.model,
					stopReason: lastAssistant.stopReason,
					errorMessage: lastAssistant.errorMessage,
				});
				emitProgress(lastAssistant.text ? "Response received, validating output..." : "Turn completed, waiting for next step...", true);
			};

			proc.stdout.on("data", (chunk) => {
				buffer += stdoutDecoder.write(chunk);
				const lines = buffer.split("\n");
				buffer = lines.pop() ?? "";
				for (const line of lines) {
					writeStdoutLogLine(line);
					processLine(line);
				}
			});

			proc.stderr.on("data", (chunk) => {
				stderrLogStream.write(chunk);
				stderrTail = appendTail(stderrTail, stderrDecoder.write(chunk), STDERR_TAIL_LIMIT);
			});

			proc.on("error", (error) => { cleanup(); reject(error); });
			proc.on("close", (code) => {
				cleanup();
				buffer += stdoutDecoder.end();
				if (buffer.trim().length > 0) {
					const finalLine = buffer.trimEnd();
					writeStdoutLogLine(finalLine);
					processLine(finalLine);
				}
				stderrTail = appendTail(stderrTail, stderrDecoder.end(), STDERR_TAIL_LIMIT);
				// E4 fix: exitCode === null (SIGKILL/OOM) must be treated as failure
				resolve(code === null ? 1 : code);
			});
		});

		await Promise.all([finalizeWriteStream(stdoutLogStream), finalizeWriteStream(stderrLogStream)]);

		const normalizedText = lastAssistant.text ? normalizeMarkdown(lastAssistant.text) : "";
		const isFailure = exitCode !== 0 || lastAssistant.stopReason === "error" || lastAssistant.stopReason === "aborted";

		if (isFailure) {
			const reason = lastAssistant.errorMessage || stderrTail.trim() || `pi subprocess failed with exit code ${exitCode}`;
			throw new Error(reason);
		}

		if (!normalizedText) {
			throw new Error("The stage finished without a final assistant text output.");
		}

		return {
			text: normalizedText,
			exitCode,
			stderr: stderrTail,
			model: lastAssistant.model ?? model,
			stopReason: lastAssistant.stopReason,
			errorMessage: lastAssistant.errorMessage,
			usage,
		};
	} finally {
		try {
			await Promise.all([finalizeWriteStream(stdoutLogStream), finalizeWriteStream(stderrLogStream)]);
		} catch {
			stdoutLogStream.destroy();
			stderrLogStream.destroy();
		}
		try {
			await fsp.unlink(tempPrompt.filePath);
		} catch {
			// Ignore cleanup errors.
		}
		try {
			await fsp.rmdir(tempPrompt.dir);
		} catch {
			// Ignore cleanup errors.
		}
	}
}

import path from "node:path";
import { promises as fs } from "node:fs";
import { extractMarkedSections } from "./marker-parser.ts";
import { generateRandomNumber } from "./number-generator.ts";
import { writeMarkdownFile, normalizeMarkdown } from "./io.ts";
import { createInitialManifest, createLoopEntry, createStageRecord, markStageFailure, markStageRunning, markStageSuccess, saveManifest } from "./manifest.ts";
import { diffSnapshots, formatSnapshotDiff, takeSnapshot, type SnapshotDiff } from "./post-hoc-check.ts";
import { ensureLoopDirectory, findNextCallNumber, prepareCallWorkspace, toProjectRelativePath } from "./path-utils.ts";
import {
	buildChecklistUserPrompt,
	buildDevelopmentUserPrompt,
	buildEvaluationUserPrompt,
	buildInitialArtifactsUserPrompt,
	buildLearningUpdateUserPrompt,
	buildReportUserPrompt,
	CHECKLIST_SYSTEM_PROMPT,
	DEVELOPMENT_SYSTEM_PROMPT,
	EVALUATION_SYSTEM_PROMPT,
	INITIAL_ARTIFACTS_SYSTEM_PROMPT,
	LEARNING_UPDATE_SYSTEM_PROMPT,
	REPORT_SYSTEM_PROMPT,
	WORKFLOW_ASSUMPTIONS,
} from "./prompts.ts";
import { runPiStage } from "./runner.ts";
import type { DirectivePolicy, PiStageStreamEvent, StageExecutionResult, StageName, StageRecord, WorkflowManifest, WorkflowProgressEvent } from "./types.ts";
import { stageDisplayName, buildStageStatusMessage } from "./ui-monitor.ts";
import { determineDirectivePolicy, extractOverallScore } from "./validation.ts";

export interface WorkflowRunInput {
	cwd: string;
	idea: string;
	loops: number;
	modelPattern?: string;
	thinkingLevel?: string;
	onStatus?: (message: string | undefined) => void;
	onEvent?: (event: WorkflowProgressEvent) => void;
	/** T3 fix: Optional invocation override for testing. */
	invocation?: { command: string; args?: string[] };
}

export interface WorkflowRunResult {
	callDir: string;
	relativeCallDir: string;
	manifest: WorkflowManifest;
	latestScore?: number;
}

function stagePaths(cwd: string, record: StageRecord): { logPath: string; stderrPath: string } {
	return {
		logPath: path.resolve(cwd, record.logPath),
		stderrPath: path.resolve(cwd, record.stderrPath),
	};
}



function emitWorkflowEvent(
	onEvent: ((event: WorkflowProgressEvent) => void) | undefined,
	event: WorkflowProgressEvent,
): void {
	onEvent?.(event);
}

function mapPiStageEventToWorkflowEvent(options: {
	event: PiStageStreamEvent;
	relativeCallDir: string;
	requestedLoops: number;
	completedLoops: number;
	stageName: StageName;
	loopNumber?: number;
}): WorkflowProgressEvent | undefined {
	const { event, relativeCallDir, requestedLoops, completedLoops, stageName, loopNumber } = options;

	switch (event.type) {
		case "tool_execution_start":
			return {
				type: "tool_start",
				relativeCallDir,
				requestedLoops,
				completedLoops,
				stageName,
				loopNumber,
				message: `Tool ${event.toolName} started`,
				toolName: event.toolName,
			};
		case "tool_execution_end":
			return {
				type: "tool_end",
				relativeCallDir,
				requestedLoops,
				completedLoops,
				stageName,
				loopNumber,
				message: event.isError ? `Tool ${event.toolName} returned an error` : `Tool ${event.toolName} completed`,
				toolName: event.toolName,
				isError: event.isError,
			};
		default:
			return undefined;
	}
}

async function runManagedStage(options: {
	cwd: string;
	protectedRoots: string[];
	modelPattern?: string;
	thinkingLevel?: string;
	record: StageRecord;
	stageName: StageName;
	loopNumber?: number;
	requestedLoops: number;
	completedLoops: number;
	relativeCallDir: string;
	systemPrompt: string;
	userPrompt: string;
	manifest: WorkflowManifest;
	manifestPath: string;
	onStatus?: (message: string | undefined) => void;
	onEvent?: (event: WorkflowProgressEvent) => void;
	statusMessage: string;
	/** T3 fix: Optional invocation override for testing. */
	invocation?: { command: string; args?: string[] };
}): Promise<StageExecutionResult> {
	const {
		cwd,
		protectedRoots,
		modelPattern,
		thinkingLevel,
		record,
		stageName,
		loopNumber,
		requestedLoops,
		completedLoops,
		relativeCallDir,
		systemPrompt,
		userPrompt,
		manifest,
		manifestPath,
		onStatus,
		onEvent,
		statusMessage,
		invocation,
	} = options;
	markStageRunning(record);
	await saveManifest(manifestPath, manifest);
	onStatus?.(statusMessage);
	emitWorkflowEvent(onEvent, {
		type: "stage_started",
		relativeCallDir,
		requestedLoops,
		completedLoops,
		message: statusMessage,
		stageName,
		stageStatus: record.status,
		loopNumber,
	});

	try {
		const paths = stagePaths(cwd, record);
		const result = await runPiStage({
			cwd,
			model: modelPattern,
			thinkingLevel,
			systemPrompt,
			userPrompt,
			logPath: paths.logPath,
			stderrPath: paths.stderrPath,
			protectedRoots,
			invocation,
			onProgress: (detail) => {
				const message = buildStageStatusMessage(statusMessage, detail);
				onStatus?.(message);
				emitWorkflowEvent(onEvent, {
					type: "stage_progress",
					relativeCallDir,
					requestedLoops,
					completedLoops,
					message,
					stageName,
					stageStatus: record.status,
					loopNumber,
				});
			},
			onEvent: (event) => {
				const mappedEvent = mapPiStageEventToWorkflowEvent({
					event,
					relativeCallDir,
					requestedLoops,
					completedLoops,
					stageName,
					loopNumber,
				});
				if (mappedEvent) emitWorkflowEvent(onEvent, mappedEvent);
			},
		});
		markStageSuccess(record, result);
		await saveManifest(manifestPath, manifest);
		emitWorkflowEvent(onEvent, {
			type: "stage_completed",
			relativeCallDir,
			requestedLoops,
			completedLoops,
			message: `Stage completed: ${stageDisplayName(stageName)}${loopNumber ? ` (loop ${loopNumber}/${requestedLoops})` : ""}`,
			stageName,
			stageStatus: record.status,
			loopNumber,
		});
		return result;
	} catch (error) {
		markStageFailure(record, error);
		await saveManifest(manifestPath, manifest);
		emitWorkflowEvent(onEvent, {
			type: "stage_failed",
			relativeCallDir,
			requestedLoops,
			completedLoops,
			message: error instanceof Error ? error.message : String(error),
			stageName,
			stageStatus: record.status,
			loopNumber,
			isError: true,
		});
		throw error;
	}
}

export async function runIdeaRefinementWorkflow(input: WorkflowRunInput): Promise<WorkflowRunResult> {
	const { cwd, idea, loops, modelPattern, thinkingLevel, onStatus, onEvent, invocation } = input;
	const callNumber = await findNextCallNumber(path.join(cwd, "docs", "idea_refinement"));
	const workspace = await prepareCallWorkspace(cwd, callNumber);
	const relativeCallDir = toProjectRelativePath(cwd, workspace.callDir);
	const manifest = createInitialManifest({
		cwd,
		workspace,
		callNumber,
		requestedLoops: loops,
		model: modelPattern,
		thinkingLevel,
		assumptions: WORKFLOW_ASSUMPTIONS,
	});

	await writeMarkdownFile(workspace.rootFiles.idea, idea);
	await saveManifest(workspace.rootFiles.manifest, manifest);
	emitWorkflowEvent(onEvent, {
		type: "workflow_started",
		relativeCallDir,
		requestedLoops: loops,
		completedLoops: 0,
		message: `Workflow started in ${relativeCallDir}`,
	});

	let latestScore: number | undefined;

	try {
		const initialRandomNumber = generateRandomNumber();
		const directivePolicy: DirectivePolicy = determineDirectivePolicy(initialRandomNumber);
		manifest.initialRandomNumber = initialRandomNumber;
		manifest.directivePolicy = directivePolicy;
		await saveManifest(workspace.rootFiles.manifest, manifest);

		const bootstrapResult = await runManagedStage({
			cwd,
			protectedRoots: [workspace.callDir],
			modelPattern,
			thinkingLevel,
			record: manifest.bootstrap,
			stageName: "bootstrap",
			requestedLoops: loops,
			completedLoops: manifest.completedLoops,
			relativeCallDir,
			systemPrompt: INITIAL_ARTIFACTS_SYSTEM_PROMPT,
			userPrompt: buildInitialArtifactsUserPrompt({
				cwd,
				workspace,
				randomNumber: initialRandomNumber,
				policy: directivePolicy,
			}),
			manifest,
			manifestPath: workspace.rootFiles.manifest,
			onStatus,
			onEvent,
			statusMessage: `Generating initial artifacts in ${relativeCallDir}`,
			invocation,
		});

		let sections: Record<string, string>;
		try {
			sections = extractMarkedSections(bootstrapResult.text, [
				"DIRECTIVE.md",
				"LEARNING.md",
				"CRITERIA.md",
				"DIAGNOSIS.md",
				"METRICS.md",
				"BACKLOG.md",
			]);
		} catch (parseError) {
			const rawPath = path.join(workspace.callDir, "bootstrap-raw.md");
			await writeMarkdownFile(rawPath, bootstrapResult.text);
			throw new Error(
				`Failed to extract bootstrap sections; raw text preserved at ${rawPath}. Cause: ${parseError instanceof Error ? parseError.message : String(parseError)}`,
			);
		}
		await writeMarkdownFile(workspace.rootFiles.directive, sections["DIRECTIVE.md"]);
		await writeMarkdownFile(workspace.rootFiles.learning, sections["LEARNING.md"]);
		await writeMarkdownFile(workspace.rootFiles.criteria, sections["CRITERIA.md"]);
		await writeMarkdownFile(workspace.rootFiles.diagnosis, sections["DIAGNOSIS.md"]);
		await writeMarkdownFile(workspace.rootFiles.metrics, sections["METRICS.md"]);
		await writeMarkdownFile(workspace.rootFiles.backlog, sections["BACKLOG.md"]);
		await saveManifest(workspace.rootFiles.manifest, manifest);

		for (let loopNumber = 1; loopNumber <= loops; loopNumber += 1) {
			const loopRandomNumber = generateRandomNumber();
			const loopDir = await ensureLoopDirectory(workspace, loopNumber);
			const loopEntry = createLoopEntry({
				cwd,
				loopNumber,
				randomNumber: loopRandomNumber,
				loopDir,
				logsDir: workspace.logsDir,
			});
			manifest.loops.push(loopEntry);
			await saveManifest(workspace.rootFiles.manifest, manifest);

			// Snapshot C7: capture before develop to detect material changes
			// C2 fix: Snapshot C7 captures project source (cwd), not extension source
			const snapshotBefore = await takeSnapshot(cwd);

			const developResult = await runManagedStage({
				cwd,
				protectedRoots: [workspace.callDir],
				modelPattern,
				thinkingLevel,
				record: loopEntry.stages.develop,
				stageName: "develop",
				loopNumber,
				requestedLoops: loops,
				completedLoops: manifest.completedLoops,
				relativeCallDir,
				systemPrompt: DEVELOPMENT_SYSTEM_PROMPT,
				userPrompt: buildDevelopmentUserPrompt({
					cwd,
					workspace,
					loopNumber,
					requestedLoops: loops,
					randomNumber: loopRandomNumber,
				}),
				manifest,
				manifestPath: workspace.rootFiles.manifest,
				onStatus,
				onEvent,
				statusMessage: `Loop ${loopNumber}/${loops}: developing RESPONSE.md`,
				invocation,
			});
			await writeMarkdownFile(workspace.rootFiles.response, developResult.text);
			await writeMarkdownFile(path.join(loopDir, "RESPONSE.md"), developResult.text);

			// Snapshot C7: compare before/after and store diff in loopEntry
			// C2 fix: Snapshot C7 after develop also uses cwd (project root)
			const snapshotAfter = await takeSnapshot(cwd);
			const c7Diff: SnapshotDiff = diffSnapshots(snapshotBefore, snapshotAfter);
			loopEntry.c7Snapshot = {
				hasChanges: c7Diff.hasChanges,
				diffSummary: formatSnapshotDiff(c7Diff),
				changedFiles: c7Diff.changed.length + c7Diff.added.length,
			};

			// If C7=0 (no material changes), emit WARNING notification
			if (!c7Diff.hasChanges) {
				const warningMsg = `⚠ Loop ${loopNumber}/${loops}: C7=0 — no material changes to source code after develop. This indicates pseudo-execution.`;
				onStatus?.(warningMsg);
				emitWorkflowEvent(onEvent, {
					type: "stage_progress",
					relativeCallDir,
					requestedLoops: loops,
					completedLoops: manifest.completedLoops,
					message: warningMsg,
					stageName: "develop",
					stageStatus: "running",
					loopNumber,
				});
			}

			const evaluateResult = await runManagedStage({
				cwd,
				protectedRoots: [workspace.callDir],
				modelPattern,
				thinkingLevel,
				record: loopEntry.stages.evaluate,
				stageName: "evaluate",
				loopNumber,
				requestedLoops: loops,
				completedLoops: manifest.completedLoops,
				relativeCallDir,
				systemPrompt: EVALUATION_SYSTEM_PROMPT,
				userPrompt: buildEvaluationUserPrompt({
					cwd,
					workspace,
					loopNumber,
					requestedLoops: loops,
				}),
				manifest,
				manifestPath: workspace.rootFiles.manifest,
				onStatus,
				onEvent,
				statusMessage: `Loop ${loopNumber}/${loops}: evaluating FEEDBACK.md`,
				invocation,
			});
			await writeMarkdownFile(workspace.rootFiles.feedback, evaluateResult.text);
			await writeMarkdownFile(path.join(loopDir, "FEEDBACK.md"), evaluateResult.text);

			loopEntry.score = extractOverallScore(evaluateResult.text);
			if (typeof loopEntry.score === "number") latestScore = loopEntry.score;

			const learningResult = await runManagedStage({
				cwd,
				protectedRoots: [workspace.callDir],
				modelPattern,
				thinkingLevel,
				record: loopEntry.stages.learning,
				stageName: "learning",
				loopNumber,
				requestedLoops: loops,
				completedLoops: manifest.completedLoops,
				relativeCallDir,
				systemPrompt: LEARNING_UPDATE_SYSTEM_PROMPT,
				userPrompt: buildLearningUpdateUserPrompt({
					cwd,
					workspace,
					loopNumber,
					requestedLoops: loops,
				}),
				manifest,
				manifestPath: workspace.rootFiles.manifest,
				onStatus,
				onEvent,
				statusMessage: `Loop ${loopNumber}/${loops}: updating LEARNING.md`,
				invocation,
			});
			const learningSections = extractMarkedSections(learningResult.text, ["LEARNING.md", "BACKLOG.md"]);
			await writeMarkdownFile(workspace.rootFiles.learning, learningSections["LEARNING.md"]);
			await writeMarkdownFile(workspace.rootFiles.backlog, learningSections["BACKLOG.md"]);
			await writeMarkdownFile(path.join(loopDir, "LEARNING.md"), learningSections["LEARNING.md"]);
			await writeMarkdownFile(path.join(loopDir, "BACKLOG.md"), learningSections["BACKLOG.md"]);

			loopEntry.completedAt = new Date().toISOString();
			manifest.completedLoops = loopNumber;
			await saveManifest(workspace.rootFiles.manifest, manifest);
			emitWorkflowEvent(onEvent, {
				type: "loop_completed",
				relativeCallDir,
				requestedLoops: loops,
				completedLoops: manifest.completedLoops,
				message: `Loop ${loopNumber}/${loops} completed${typeof loopEntry.score === "number" ? ` • score ${loopEntry.score}/100` : ""}`,
				loopNumber,
				score: loopEntry.score,
			});
		}

		// === Final consolidation stages: REPORT.md and CHECKLIST.md ===
		// After all loops, generate the two final artifacts that consolidate the entire investigation.

		// C1 fix: Use manifest.report directly instead of creating a local StageRecord
		const reportResult = await runManagedStage({
			cwd,
			protectedRoots: [workspace.callDir],
			modelPattern,
			thinkingLevel,
			record: manifest.report,
			stageName: "report",
			requestedLoops: loops,
			completedLoops: manifest.completedLoops,
			relativeCallDir,
			systemPrompt: REPORT_SYSTEM_PROMPT,
			userPrompt: buildReportUserPrompt({
				cwd,
				workspace,
				requestedLoops: loops,
				completedLoops: manifest.completedLoops,
			}),
			manifest,
			manifestPath: workspace.rootFiles.manifest,
			onStatus,
			onEvent,
			statusMessage: `Consolidating final report: REPORT.md`,
			invocation,
		});
		await writeMarkdownFile(workspace.rootFiles.report, reportResult.text);

		// C1 fix: Use manifest.checklist directly instead of creating a local StageRecord
		const checklistResult = await runManagedStage({
			cwd,
			protectedRoots: [workspace.callDir],
			modelPattern,
			thinkingLevel,
			record: manifest.checklist,
			stageName: "checklist",
			requestedLoops: loops,
			completedLoops: manifest.completedLoops,
			relativeCallDir,
			systemPrompt: CHECKLIST_SYSTEM_PROMPT,
			userPrompt: buildChecklistUserPrompt({
				cwd,
				workspace,
				requestedLoops: loops,
				completedLoops: manifest.completedLoops,
			}),
			manifest,
			manifestPath: workspace.rootFiles.manifest,
			onStatus,
			onEvent,
			statusMessage: `Generating action checklist: CHECKLIST.md`,
			invocation,
		});
		await writeMarkdownFile(workspace.rootFiles.checklist, checklistResult.text);

		// O4 fix: workflow_completed emitted AFTER report and checklist stages complete
		manifest.status = "success";
		manifest.completedAt = new Date().toISOString();
		await saveManifest(workspace.rootFiles.manifest, manifest);
		onStatus?.(`Workflow completed in ${relativeCallDir}`);
		emitWorkflowEvent(onEvent, {
			type: "workflow_completed",
			relativeCallDir,
			requestedLoops: loops,
			completedLoops: manifest.completedLoops,
			message: `Workflow completed in ${relativeCallDir}`,
			score: latestScore,
		});

		return {
			callDir: workspace.callDir,
			relativeCallDir,
			manifest,
			latestScore,
		};
	} catch (error) {
		manifest.status = "failed";
		manifest.completedAt = new Date().toISOString();
		manifest.lastError = error instanceof Error ? error.message : String(error);
		await saveManifest(workspace.rootFiles.manifest, manifest);
		onStatus?.(`Workflow failed: ${manifest.lastError}`);
		emitWorkflowEvent(onEvent, {
			type: "workflow_failed",
			relativeCallDir,
			requestedLoops: loops,
			completedLoops: manifest.completedLoops,
			message: `Workflow failed: ${manifest.lastError}`,
			isError: true,
		});
		throw error;
	}
}

import path from "node:path";
