export function createStageRecord(name: StageName, logPath: string, stderrPath: string): StageRecord {
	return {
		name,
		status: "pending",
		logPath,
		stderrPath,
	};
}

export function createInitialManifest(options: {
	cwd: string;
	workspace: CallWorkspace;
	callNumber: number;
	requestedLoops: number;
	model?: string;
	thinkingLevel?: string;
	assumptions: string[];
}): WorkflowManifest {
	const { cwd, workspace, callNumber, requestedLoops, model, thinkingLevel, assumptions } = options;
	const relativeCallDir = toProjectRelativePath(cwd, workspace.callDir);

	return {
		schemaVersion: 1,
		status: "running",
		cwd,
		callNumber,
		callId: relativeCallDir.split("/").pop() ?? relativeCallDir,
		callDir: relativeCallDir,
		startedAt: new Date().toISOString(),
		requestedLoops,
		completedLoops: 0,
		model,
		thinkingLevel,
		files: {
			idea: toProjectRelativePath(cwd, workspace.rootFiles.idea),
			directive: toProjectRelativePath(cwd, workspace.rootFiles.directive),
			learning: toProjectRelativePath(cwd, workspace.rootFiles.learning),
			criteria: toProjectRelativePath(cwd, workspace.rootFiles.criteria),
			diagnosis: toProjectRelativePath(cwd, workspace.rootFiles.diagnosis),
			metrics: toProjectRelativePath(cwd, workspace.rootFiles.metrics),
			backlog: toProjectRelativePath(cwd, workspace.rootFiles.backlog),
			response: toProjectRelativePath(cwd, workspace.rootFiles.response),
			feedback: toProjectRelativePath(cwd, workspace.rootFiles.feedback),
			report: toProjectRelativePath(cwd, workspace.rootFiles.report),
			checklist: toProjectRelativePath(cwd, workspace.rootFiles.checklist),
		},
		bootstrap: createStageRecord(
			"bootstrap",
			toProjectRelativePath(cwd, `${workspace.logsDir}/bootstrap.jsonl`),
			toProjectRelativePath(cwd, `${workspace.logsDir}/bootstrap.stderr.log`),
		),
		report: createStageRecord(
			"report",
			toProjectRelativePath(cwd, `${workspace.logsDir}/report.jsonl`),
			toProjectRelativePath(cwd, `${workspace.logsDir}/report.stderr.log`),
		),
		checklist: createStageRecord(
			"checklist",
			toProjectRelativePath(cwd, `${workspace.logsDir}/checklist.jsonl`),
			toProjectRelativePath(cwd, `${workspace.logsDir}/checklist.stderr.log`),
		),
		loops: [],
		assumptions,
	};
}

export function createLoopEntry(options: {
	cwd: string;
	loopNumber: number;
	randomNumber: number;
	loopDir: string;
	logsDir: string;
}): LoopManifestEntry {
	const { cwd, loopNumber, randomNumber, loopDir, logsDir } = options;
	const prefix = `loop_${String(loopNumber).padStart(2, "0")}`;

	return {
		loopNumber,
		randomNumber,
		startedAt: new Date().toISOString(),
		responsePath: toProjectRelativePath(cwd, `${loopDir}/RESPONSE.md`),
		feedbackPath: toProjectRelativePath(cwd, `${loopDir}/FEEDBACK.md`),
		learningPath: toProjectRelativePath(cwd, `${loopDir}/LEARNING.md`),
		stages: {
			develop: createStageRecord(
				"develop",
				toProjectRelativePath(cwd, `${logsDir}/${prefix}_develop.jsonl`),
				toProjectRelativePath(cwd, `${logsDir}/${prefix}_develop.stderr.log`),
			),
			evaluate: createStageRecord(
				"evaluate",
				toProjectRelativePath(cwd, `${logsDir}/${prefix}_evaluate.jsonl`),
				toProjectRelativePath(cwd, `${logsDir}/${prefix}_evaluate.stderr.log`),
			),
			learning: createStageRecord(
				"learning",
				toProjectRelativePath(cwd, `${logsDir}/${prefix}_learning.jsonl`),
				toProjectRelativePath(cwd, `${logsDir}/${prefix}_learning.stderr.log`),
			),
		},
	};
}

export function markStageRunning(record: StageRecord): void {
	record.status = "running";
	record.startedAt = new Date().toISOString();
	record.completedAt = undefined;
	record.exitCode = undefined;
	record.errorMessage = undefined;
	record.stopReason = undefined;
	record.usage = undefined;
}

export function markStageSuccess(record: StageRecord, result: StageExecutionResult): void {
	record.status = "success";
	record.completedAt = new Date().toISOString();
	record.exitCode = result.exitCode;
	record.model = result.model;
	record.stopReason = result.stopReason;
	record.errorMessage = result.errorMessage;
	record.usage = result.usage;
}

export function markStageFailure(record: StageRecord, error: unknown): void {
	record.status = "failed";
	record.completedAt = new Date().toISOString();
	record.errorMessage = error instanceof Error ? error.message : String(error);
}

export async function saveManifest(manifestPath: string, manifest: WorkflowManifest): Promise<void> {
	await writeJsonFile(manifestPath, manifest);
}

/**
 * post-hoc-check.ts — SHA256 snapshot of the source-code directory
 *
 * Purpose: Detect whether a "develop" loop actually changed .ts files
 * in the extension directory, providing material evidence of execution
 * vs. pseudo-execution.
 *
 * Mechanism:
 * 1. Before develop: take SHA256 snapshot of all .ts files in the directory
 * 2. After develop: take a new snapshot and compare
 * 3. Returns list of changed files (or empty if none)
 *
 * This feeds criterion C7 (Material Execution) of FEEDBACK.md.
 */

import { createHash } from "node:crypto";
import { promises as fs, type Dirent } from "node:fs";
import path from "node:path";

export interface FileSnapshot {
	[relativePath: string]: string; // SHA256 hex digest
}

export interface SnapshotDiff {
	changed: string[];       // files with different hash
	added: string[];         // new files
	removed: string[];       // files that disappeared
	hasChanges: boolean;     // true if changed + added + removed > 0
}

/**
 * Takes a SHA256 snapshot of .ts files in the extension root directory.
 * Returns a map of relative path → hash.
 * If the directory does not exist, returns an empty object.
 */
export async function takeSnapshot(extensionRoot: string): Promise<FileSnapshot> {
	const snapshot: FileSnapshot = {};

	try {
		await fs.access(extensionRoot);
	} catch {
		return snapshot;
	}

	async function walkDir(dir: string): Promise<void> {
		let entries: Dirent[];
		try {
			entries = await fs.readdir(dir, { withFileTypes: true });
		} catch {
			return;
		}

		for (const entry of entries) {
			const fullPath = path.join(dir, entry.name);
			if (entry.isDirectory() && entry.name !== "node_modules" && !entry.name.startsWith(".")) {
				await walkDir(fullPath);
			} else if (entry.isFile() && entry.name.endsWith(".ts")) {
				const relPath = path.relative(extensionRoot, fullPath);
				try {
					const content = await fs.readFile(fullPath, "utf-8");
					snapshot[relPath] = createHash("sha256").update(content, "utf-8").digest("hex");
				} catch {
					// skip unreadable files
				}
			}
		}
	}

	await walkDir(extensionRoot);
	return snapshot;
}

/**
 * Compares two snapshots and returns the differences.
 */
export function diffSnapshots(before: FileSnapshot, after: FileSnapshot): SnapshotDiff {
	const changed: string[] = [];
	const added: string[] = [];
	const removed: string[] = [];

	const allFiles = new Set([...Object.keys(before), ...Object.keys(after)]);

	for (const file of allFiles) {
		const beforeHash = before[file];
		const afterHash = after[file];

		if (beforeHash && !afterHash) {
			removed.push(file);
		} else if (!beforeHash && afterHash) {
			added.push(file);
		} else if (beforeHash && afterHash && beforeHash !== afterHash) {
			changed.push(file);
		}
	}

	return {
		changed,
		added,
		removed,
		hasChanges: changed.length > 0 || added.length > 0 || removed.length > 0,
	};
}

/**
 * Formats the diff for inclusion in a notification or diagnosis.
 */
export function formatSnapshotDiff(diff: SnapshotDiff): string {
	const parts: string[] = [];

	if (diff.changed.length > 0) {
		parts.push(`changed (${diff.changed.length}): ${diff.changed.join(", ")}`);
	}
	if (diff.added.length > 0) {
		parts.push(`added (${diff.added.length}): ${diff.added.join(", ")}`);
	}
	if (diff.removed.length > 0) {
		parts.push(`removed (${diff.removed.length}): ${diff.removed.join(", ")}`);
	}

	if (parts.length === 0) {
		return "No material changes detected in source code.";
	}

	return parts.join("; ");
}

import path from "node:path";
import type { ExtensionAPI, ExtensionCommandContext } from "@mariozechner/pi-coding-agent";
import {
	applyIdeaRefinementProgressEvent,
	buildIdeaRefinementStatusLine,
	buildIdeaRefinementWidgetLines,
	createIdeaRefinementMonitorState,
	setIdeaRefinementMonitorDetail,
	stageDisplayName,
} from "./lib/ui-monitor.ts";
import { runIdeaRefinementWorkflow } from "./lib/workflow.ts";
import { parsePositiveInteger } from "./lib/validation.ts";
import { runResponseValidatorCheck } from "./lib/validator-check.ts";

const STATUS_KEY = "idea-refinement";
const WIDGET_KEY = "idea-refinement-monitor";
const RENDER_DEBOUNCE_MS = 150;

function shouldNotifyProgressEvent(event: Parameters<typeof applyIdeaRefinementProgressEvent>[1]): boolean {
	switch (event.type) {
		case "workflow_started":
		case "stage_started":
		case "stage_completed":
		case "stage_failed":
		case "loop_completed":
		case "workflow_completed":
		case "workflow_failed":
			return true;
		default:
			return false;
	}
}

function progressEventLevel(event: Parameters<typeof applyIdeaRefinementProgressEvent>[1]): "info" | "warning" | "error" {
	if (event.type === "stage_failed" || event.type === "workflow_failed" || event.isError) return "error";
	return "info";
}

async function collectIdea(args: string, ctx: ExtensionCommandContext): Promise<string | undefined> {
	const inlineIdea = args.trim();
	if (inlineIdea.length > 0) {
		return inlineIdea;
	}

	const editorResult = await ctx.ui.editor("Describe the idea to be refined", "");
	const idea = editorResult?.trim();
	return idea && idea.length > 0 ? idea : undefined;
}

async function collectLoopCount(ctx: ExtensionCommandContext): Promise<number | undefined> {
	while (true) {
		const input = await ctx.ui.input("How many development loops do you want to run?", "Enter a positive integer");
		if (input === undefined) return undefined;

		const parsed = parsePositiveInteger(input);
		if (parsed !== undefined) return parsed;

		ctx.ui.notify("Invalid value. Enter a positive integer.", "warning");
	}
}

function getCurrentModelPattern(ctx: ExtensionCommandContext): string | undefined {
	if (!ctx.model) return undefined;
	return `${ctx.model.provider}/${ctx.model.id}`;
}

export default function ideaRefinementExtension(pi: ExtensionAPI) {
	let runInProgress = false;

	pi.registerCommand("idea-refine", {
		description: "Runs the forced iterative idea-refinement workflow",
		handler: async (args, ctx) => {
			if (!ctx.hasUI) {
				ctx.ui.notify("/idea-refine requires interactive mode.", "error");
				return;
			}

			if (!ctx.model) {
				ctx.ui.notify("Select a model before running /idea-refine.", "error");
				return;
			}

			if (!ctx.isIdle()) {
				ctx.ui.notify("Wait for the current agent to finish before starting /idea-refine.", "warning");
				return;
			}

			if (runInProgress) {
				ctx.ui.notify("An idea-refinement run is already in progress.", "warning");
				return;
			}

			const idea = await collectIdea(args, ctx);
			if (!idea) {
				ctx.ui.notify("Run canceled: no idea was provided.", "info");
				return;
			}

			const loops = await collectLoopCount(ctx);
			if (loops === undefined) {
				ctx.ui.notify("Run canceled before loop count was defined.", "info");
				return;
			}

			const monitorState = createIdeaRefinementMonitorState();
			let renderTimer: ReturnType<typeof setTimeout> | undefined;
			let lastConsoleEventMessage: string | undefined;
			let lastWorkingMessage: string | undefined;

			const setWorking = (message: string | undefined) => {
				const limited = message && message.length > 80 ? `${message.slice(0, 77)}...` : message;
				if (limited !== lastWorkingMessage) {
					lastWorkingMessage = limited;
					ctx.ui.setWorkingMessage?.(limited);
				}
			};

			const renderMonitor = () => {
				const statusLine = buildIdeaRefinementStatusLine(monitorState);
				ctx.ui.setStatus(STATUS_KEY, statusLine);
				// P1-3: Distinct channels.
				// setStatus = state summary (loop, stage, score) — already built into statusLine.
				// setWorkingMessage = current action detail — managed by the active spinner.
				ctx.ui.setWidget(WIDGET_KEY, buildIdeaRefinementWidgetLines(monitorState));
			};

			const scheduleRender = (immediate = false) => {
				if (immediate) {
					if (renderTimer) {
						clearTimeout(renderTimer);
						renderTimer = undefined;
					}
					renderMonitor();
					return;
				}

				if (renderTimer) return;
				renderTimer = setTimeout(() => {
					renderTimer = undefined;
					renderMonitor();
				}, RENDER_DEBOUNCE_MS);
			};

			const updateUiStatus = (message: string | undefined) => {
				setIdeaRefinementMonitorDetail(monitorState, message);
				setWorking(message);
				scheduleRender(true);
			};

			const handleProgressEvent = (event: Parameters<typeof applyIdeaRefinementProgressEvent>[1]) => {
				applyIdeaRefinementProgressEvent(monitorState, event);
				if (shouldNotifyProgressEvent(event) && event.message !== lastConsoleEventMessage) {
					lastConsoleEventMessage = event.message;
					ctx.ui.notify(event.message, progressEventLevel(event));
				}
				scheduleRender(true);
			};

			runInProgress = true;
			// Clear dedup cache when starting a new run
			lastWorkingMessage = undefined;
			ctx.ui.setWorkingVisible?.(true);
			ctx.ui.setWorkingIndicator?.({ frames: ["⠋","⠙","⠹","⠸","⠼","⠴","⠦","⠧","⠇","⠏"], intervalMs: 80 });
			ctx.ui.notify(`Starting /idea-refine with ${loops} loop(s). Progress will be shown in the console and monitor.`, "info");
			setWorking("Initializing workflow monitor...");

			try {
				const result = await runIdeaRefinementWorkflow({
					cwd: ctx.cwd,
					idea,
					loops,
					modelPattern: getCurrentModelPattern(ctx),
					onStatus: updateUiStatus,
					onEvent: handleProgressEvent,
				});

				// P1 #6: Validates RESPONSE.md with epistemic validator (async, non-critical)
				const responsePath = path.join(result.callDir, "RESPONSE.md");
				// C4 fix: Log errors instead of silently swallowing
				runResponseValidatorCheck(responsePath).catch((err) => {
					console.error("[idea-refinement] Validator check failed:", err);
				});

				scheduleRender(true);
				const lastScoreSuffix = typeof result.latestScore === "number" ? ` • final score ${result.latestScore}/100` : "";
				ctx.ui.notify(`Idea refinement completed: ${result.relativeCallDir}${lastScoreSuffix}`, "info");
			} catch (error) {
				const message = error instanceof Error ? error.message : String(error);
				if (monitorState.workflowStatus !== "failed") {
					handleProgressEvent({
						type: "workflow_failed",
						relativeCallDir: monitorState.relativeCallDir ?? "",
						requestedLoops: loops,
						completedLoops: monitorState.completedLoops,
						message: `Workflow failed: ${message}`,
						isError: true,
					});
				}
				scheduleRender(true);
				ctx.ui.notify(`Idea refinement workflow failed: ${message}`, "error");
			} finally {
				runInProgress = false;
				if (renderTimer) {
					clearTimeout(renderTimer);
					renderTimer = undefined;
				}
				ctx.ui.setWorkingIndicator?.();
				ctx.ui.setStatus(STATUS_KEY, undefined);
				ctx.ui.setWorkingMessage?.(undefined);
				ctx.ui.setWorkingVisible?.(false);
			}
		},
	});
}

